 55→/**
 56→ * "Deck Search": A dialog allowing the user to select a deck from a list of decks.
 57→ *
 58→ * * Allows filtering of visible decks based on name (searching): [DecksFilter]
 59→ * * Allows adding a new deck: [showDeckDialog]
 60→ * * Allows adding a subdeck via long-pressing a deck: [showSubDeckDialog]
 61→ *
 62→ * It is opened when the user wants a deck in stats, browser or note editor.
 63→ *
 64→ * @see SelectableDeck The data that is displayed
 65→ */
 66→@NeedsTest("simulate 'don't keep activities'")
 67→open class DeckSelectionDialog : AnalyticsDialogFragment() {
 68→    private var mDialog: MaterialDialog? = null
 69→    override fun onCreate(savedInstanceState: Bundle?) {
 70→        super.onCreate(savedInstanceState)
 71→        isCancelable = true
 72→    }
 73→
 74→    @Suppress("Deprecation") // Material dialog neutral button deprecation
 75→    override fun onCreateDialog(savedInstanceState: Bundle?): Dialog {
 76→        val dialogView = LayoutInflater.from(activity)
 77→            .inflate(R.layout.deck_picker_dialog, null, false)
 78→        val summary = dialogView.findViewById<TextView>(R.id.deck_picker_dialog_summary)
 79→        val arguments = requireArguments()
 80→        if (getSummaryMessage(arguments) == null) {
 81→            summary.visibility = View.GONE
 82→        } else {
 83→            summary.visibility = View.VISIBLE
 84→            summary.text = getSummaryMessage(arguments)
 85→        }
 86→        val recyclerView: RecyclerView = dialogView.findViewById(R.id.deck_picker_dialog_list)
 87→        recyclerView.requestFocus()
 88→        val deckLayoutManager: RecyclerView.LayoutManager = LinearLayoutManager(requireActivity())
 89→        recyclerView.layoutManager = deckLayoutManager
 90→        val dividerItemDecoration = DividerItemDecoration(recyclerView.context, DividerItemDecoration.VERTICAL)
 91→        recyclerView.addItemDecoration(dividerItemDecoration)
 92→        val decks: List<SelectableDeck> = getDeckNames(arguments)
 93→        val adapter = DecksArrayAdapter(decks)
 94→        recyclerView.adapter = adapter
 95→        adjustToolbar(dialogView, adapter)
 96→        val args = requireArguments()
 97→        if (args.containsKey("currentDeckId")) {
 98→            val did = args.getLong("currentDeckId")
 99→            recyclerView.scrollToPosition(getPositionOfDeck(did, adapter.getCurrentlyDisplayedDecks()))
100→        }
101→        mDialog = MaterialDialog(requireActivity())
102→            .negativeButton(R.string.dialog_cancel)
103→            .customView(view = dialogView, noVerticalPadding = true)
104→        if (arguments.getBoolean(KEEP_RESTORE_DEFAULT_BUTTON)) {
105→            (mDialog as MaterialDialog).positiveButton(R.string.restore_default) {
106→                onDeckSelected(null)
107→            }
108→        }
109→        return mDialog!!
110→    }
111→
112→    private fun getPositionOfDeck(did: DeckId, decks: List<SelectableDeck>) =
113→        decks.indexOfFirst { it.deckId == did }
114→
115→    private fun getSummaryMessage(arguments: Bundle): String? {
116→        return arguments.getString(SUMMARY_MESSAGE)
117→    }
118→
119→    private fun getDeckNames(arguments: Bundle): ArrayList<SelectableDeck> =
120→        BundleCompat.getParcelableArrayList(arguments, DECK_NAMES, SelectableDeck::class.java)!!
121→
122→    private val title: String
123→        get() = requireArguments().getString(TITLE)!!
124→
125→    private fun adjustToolbar(dialogView: View, adapter: DecksArrayAdapter) {
126→        val toolbar: Toolbar = dialogView.findViewById(R.id.deck_picker_dialog_toolbar)
127→        toolbar.title = title
128→        toolbar.inflateMenu(R.menu.deck_picker_dialog_menu)
129→        val searchItem = toolbar.menu.findItem(R.id.deck_picker_dialog_action_filter)
130→        val searchView = searchItem.actionView as SearchView
131→        searchView.queryHint = getString(R.string.deck_picker_dialog_filter_decks)
132→        searchView.setOnQueryTextListener(object : SearchView.OnQueryTextListener {
133→            override fun onQueryTextSubmit(query: String): Boolean {
134→                searchView.clearFocus()
135→                return true
136→            }
137→
138→            override fun onQueryTextChange(newText: String): Boolean {
139→                adapter.filter.filter(newText)
140→                return true
141→            }
142→        })
143→        val addDecks = toolbar.menu.findItem(R.id.deck_picker_dialog_action_add_deck)
144→        addDecks.setOnMenuItemClickListener {
145→            // creating new deck without any parent deck
146→            showDeckDialog()
147→            true
148→        }
149→    }
150→
151→    private fun showSubDeckDialog(parentDeckPath: String) {
152→        launchCatchingTask {
153→            val parentId = withCol { decks.id(parentDeckPath) }
154→            val createDeckDialog = CreateDeckDialog(requireActivity(), R.string.create_subdeck, CreateDeckDialog.DeckDialogType.SUB_DECK, parentId)
155→            createDeckDialog.setOnNewDeckCreated { id: Long? ->
156→                // a sub deck was created
157→                launchCatchingTask {
158→                    val name = withCol {
159→                        decks.name(id!!)
160→                    }
161→                    selectDeckWithDeckName(name)
162→                }
163→            }
164→            createDeckDialog.showDialog()
165→        }
166→    }
167→
168→    private fun showDeckDialog() {
169→        val createDeckDialog = CreateDeckDialog(requireActivity(), R.string.new_deck, CreateDeckDialog.DeckDialogType.DECK, null)
170→        // todo
171→        // setOnNewDeckCreated parameter to be made non null
172→        createDeckDialog.setOnNewDeckCreated { id: Long? ->
173→            // a deck was created
174→            launchCatchingTask {
175→                val name = withCol { decks.name(id!!) }
176→                selectDeckWithDeckName(name)
177→            }
178→        }
179→        createDeckDialog.showDialog()
180→    }
181→
182→    /**
183→     * Create the deck if it does not exists.
184→     * If name is valid, send the deck with this name to listener and close the dialog.
185→     */
186→    private fun selectDeckWithDeckName(deckName: String) {
187→        launchCatchingTask {
188→            val id = withCol { decks.id(deckName) }
189→            val dec = SelectableDeck(id, deckName)
190→            selectDeckAndClose(dec)
191→        }
192→    }
193→
194→    /**
195→     * @param deck deck sent to the listener.
196→     */
197→    private fun onDeckSelected(deck: SelectableDeck?) {
198→        deckSelectionListener!!.onDeckSelected(deck)
199→    }
200→
201→    @KotlinCleanup("Use a factory here")
202→    var deckSelectionListener: DeckSelectionListener? = null
203→        get() {
204→            if (field != null) {
205→                return field
206→            }
207→            val activity: Activity = requireActivity()
208→            if (activity is DeckSelectionListener) {
209→                return activity
210→            }
211→            val parentFragment = parentFragment
212→            if (parentFragment is DeckSelectionListener) {
213→                return parentFragment
214→            }
215→            throw IllegalStateException("Neither activity or parent fragment were a selection listener")
216→        }
217→
218→    /**
219→     * Same action as pressing on the deck in the list. I.e. send the deck to listener and close the dialog.
220→     */
221→    protected fun selectDeckAndClose(deck: SelectableDeck) {
222→        onDeckSelected(deck)
223→        mDialog!!.dismiss()
224→    }
225→
226→    protected fun displayErrorAndCancel() {
227→        mDialog!!.dismiss()
228→    }
