2078→    private fun convertSelectedTextToCloze(textBox: FieldEditText, addClozeType: AddClozeType) {
2079→        var nextClozeIndex = nextClozeIndex
2080→        if (addClozeType == AddClozeType.SAME_NUMBER) {
2081→            nextClozeIndex -= 1
2082→        }
2083→        val prefix = "{{c" + max(1, nextClozeIndex) + "::"
